use std::fs;
use super::{resolve, ShellWord};
pub(crate) fn execute(workspace: &super::WorkspaceRoot, args: &[ShellWord]) -> Result<String, String> { if !(1..=2).contains(&args.len()) { return Err("failed to parse `inspect` input: usage: `strings <path> [literal]`".into()); } let (_, path) = resolve(workspace, &args[0].value)?; let data = fs::read(&path).map_err(|e| format!("failed to read {}: {e}", path.display()))?; let literal = args.get(1).map(|arg| arg.value.as_str()); let mut out = String::new(); let mut run = Vec::new(); let mut offset = 0usize; let mut matches = 0; for (index, byte) in data.iter().enumerate().chain(std::iter::once((data.len(), &0))) { if byte.is_ascii_graphic() || *byte == b' ' { if run.is_empty() { offset = index; } run.push(*byte); } else { if run.len() >= 4 { let text = String::from_utf8_lossy(&run); if literal.is_none_or(|value| text.contains(value)) { if matches < 100 { out.push_str(&format!("{offset} {text}\n")); } matches += 1; } } run.clear(); } } if matches == 0 { out.push_str("no results\n"); } else if matches > 100 { out.push_str("[strings output truncated: showing first 100 results]\n"); } Ok(out) }
